from typing import Iterator

def split_markdown_sections(text: str) -> Iterator[str]:
    lines = text.splitlines()
    current_section: list[str] = []
    for line in lines:
        if line.startswith("## "):
            if current_section:
                yield "\n".join(current_section)
            current_section = [line]
        else:
            current_section.append(line)
    if current_section:
        yield "\n".join(current_section)

